9	export function quote(
10	  policy: { customer: { years: number }; items: { type: string }[] },
11	  _options: { isFollowUp: boolean }
12	): { premium: number } {
13	  if (policy.items.length === 0) return { premium: PROCESSING_FEE };
14	  const base = BASE_PRICE[policy.items[0].type];
15	  const premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
16	  return { premium };
17	}
